function redFlagsSection(city, cd) {
  const flags = [
    { title: `Ignoring ${city} irrigation restrictions`, body: cd.irrigationRegsPara },
    { title: `Plant selection mismatched to ${city} climate`, body: cd.nativePlantPalettePara },
    { title: `No soil amendment plan for ${city} conditions`, body: cd.soilAmendmentPara },
    { title: `HOA or historic-district review skipped`, body: cd.HOAAestheticPara },
    { title: `Tree removal without ${city} permit`, body: cd.treeServicePara },
    { title: `Invasive species or pest risk unaddressed`, body: cd.invasivePestPara }
  ];
  const flagsHTML = flags.map(f => `
<div class="fp-flag">
<h3>${f.title}</h3>
<p>${f.body}</p>
</div>`).join("");
  return `
<section class="section fp-section">
<h2>${city} Landscaping Red Flags</h2>
${flagsHTML}
</section>`;
}
